from collections import defaultdict

class Solution:
    def lengthOfLongestSubstringTwoDistinct(self, s: str) -> int:
        freq: dict[str, int] = defaultdict(int)
        left = 0
        max_len = 0

        for right, c in enumerate(s):
            freq[c] += 1

            while len(freq) > 2:
                left_char = s[left]
                freq[left_char] -= 1
                if freq[left_char] == 0:
                    del freq[left_char]
                left += 1

            max_len = max(max_len, right - left + 1)

        return max_len
